import React from "react";
import { Row } from "antd";
import { useAdminPanelPageHooks } from "./admin-panel-page-hooks";
import { Button } from "semantic-ui-react";
import { NavLink, Switch, Route } from "react-router-dom";
import VideoLogsPage from "./components/video-logs";
import ErrorLogsPage from "./components/error-logs";
import EquipmentInfoRecordPage from "./components/equipment-info-record";
import EquipmentHealthRecordHistoryPage from "./components/equipment-health-record-history";
import ActivityLogsPage from "./components/activity-logs";
import SparePartsStockPage from "./components/spare-parts-stock";
import RecommendationApprovalPage from "./components/recommendation-approval";
import RecommendationPanelPage from "./components/recommendation-panel";

const AdminPanelPage = () => {
  useAdminPanelPageHooks();
  return (
    <Switch>
      <Route path="/admin-panel" exact>
        <OptionsPage />
      </Route>
      <Route path="/admin-panel/video-logs" exact>
        <VideoLogsPage />
      </Route>
      <Route path="/admin-panel/error-logs" exact>
        <ErrorLogsPage />
      </Route>
      <Route path="/admin-panel/equipment-info-record-database" exact>
        <EquipmentInfoRecordPage />
      </Route>
      <Route path="/admin-panel/equipment-health-record-history-database" exact>
        <EquipmentHealthRecordHistoryPage />
      </Route>
      <Route path="/admin-panel/activity-logs" exact>
        <ActivityLogsPage />
      </Route>
      <Route path="/admin-panel/spare-parts-stock-database" exact>
        <SparePartsStockPage />
      </Route>
      <Route path="/admin-panel/recommendation-approval-cm" exact>
        <RecommendationApprovalPage />
      </Route>
      <Route path="/admin-panel/recommendation-panel-pm" exact>
        <RecommendationPanelPage />
      </Route>
    </Switch>
  );
};

const OptionsPage = () => {
  return (
    <div
      style={{
        paddingTop: "3%",
      }}
    >
      <Row>
        <div
          style={{
            fontSize: "5vh",
            fontWeight: "bold",
            marginBottom: "5vh",
            fontFamily: "Lato",
          }}
        >
          Admin Panel Menu
        </div>
        <Button
          as={NavLink}
          to="/admin-panel/video-logs"
          content="Video logs"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
        <Button
          as={NavLink}
          to="/admin-panel/error-logs"
          content="Error logs"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
        <Button
          as={NavLink}
          to="/admin-panel/equipment-info-record-database"
          content="Equipment Info Record"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
        <Button
          as={NavLink}
          to="/admin-panel/equipment-health-record-history-database"
          content="Equipment Health Record History"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
      </Row>
      <br></br>
      <Row>
        <Button
          as={NavLink}
          to="/admin-panel/activity-logs"
          content="Activity Logs"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
        <Button
          as={NavLink}
          to="/admin-panel/spare-parts-stock-database"
          content="Spare Parts Stock"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
        <Button
          as={NavLink}
          to="/admin-panel/recommendation-approval-cm"
          content="Recommendation Approval (CM)"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
        <Button
          as={NavLink}
          to="/admin-panel/recommendation-panel-pm"
          content="Recommendation Panel (PM)"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginRight: "1vh",
            width: "20vw",
            height: "10vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
      </Row>
    </div>
  );
};

export default AdminPanelPage;
